const crypto = require('crypto');
const secret = process.env.REELSFLOW_SIGNATURE_SECRET || 'sua-chave-secreta-para-assinatura-hmac-aqui';

const webhookData = $input.first().json;
const headers = webhookData.headers || {};
const body = webhookData.body || {};
const signature = headers['x-reelsflow-signature'] || headers['X-ReelsFlow-Signature'];

if (!signature) {
  throw new Error('Cabeçalho X-ReelsFlow-Signature ausente!');
}

// O Next.js envia o corpo como string JSON bruta compacta
const payloadStr = JSON.stringify(body);
const computedHmac = crypto.createHmac('sha256', secret).update(payloadStr).digest('hex');

if (computedHmac !== signature) {
  throw new Error('Assinatura HMAC inválida!');
}

// 1. Assinatura para 'scripting'
const scriptingPayload = {
  job_id: body.job_id,
  status: 'scripting',
  user_id: body.user_id
};
const scriptingSignature = crypto.createHmac('sha256', secret).update(JSON.stringify(scriptingPayload)).digest('hex');

return [{
  json: {
    job_id: body.job_id,
    prompt_input: body.prompt_input,
    user_id: body.user_id,
    scripting: {
      payload: scriptingPayload,
      signature: scriptingSignature
    }
  }
}];

