const contentStr = $input.first().json.choices[0].message.content;
const parsed = JSON.parse(contentStr);
const fullText = parsed.subtitles.map(s => s.text).join(' ');
return [{
  json: {
    script: parsed,
    full_text: fullText
  }
}];

const script = $node["Parse & Extract JSON"].json.script;
const tags = script.b_roll_tags || [];
const pexelsKey = process.env.PEXELS_API_KEY || 'sua-chave-pexels-aqui';

const videoUrls = [];

for (const tag of tags) {
  try {
    const response = await fetch(`https://api.pexels.com/v1/videos/search?query=${encodeURIComponent(tag)}&orientation=portrait&per_page=3`, {
      headers: {
        'Authorization': pexelsKey
      }
    });
    if (response.ok) {
      const data = await response.json();
      if (data.videos && data.videos.length > 0) {
        const video = data.videos[0];
        const file = video.video_files.find(f => f.file_type === 'video/mp4' || f.link.includes('.mp4'));
        if (file) {
          videoUrls.push(file.link);
        }
      }
    }
  } catch (err) {
    console.error(`Erro ao buscar vídeo do Pexels para tag "${tag}":`, err.message);
  }
}

return [{
  json: {
    video_urls: videoUrls
  }
}];

const crypto = require('crypto');
const secret = process.env.REELSFLOW_SIGNATURE_SECRET || 'sua-chave-secreta-para-assinatura-hmac-aqui';

const jobId = $node["Verify HMAC Signature"].json.job_id;
const userId = $node["Verify HMAC Signature"].json.user_id;
const r2AccountId = process.env.R2_ACCOUNT_ID || '';
const r2BucketName = process.env.R2_BUCKET_NAME || 'reelsflow';

let audioUrl = `https://${r2AccountId}.r2.cloudflarestorage.com/${r2BucketName}/audio/${jobId}.mp3`;
if (r2AccountId.includes('supabase') || !r2AccountId) {
  audioUrl = `https://ldubgbeidvjshwubgskp.supabase.co/storage/v1/object/public/reelsflow/audio/${jobId}.mp3`;
}

const videoUrls = $node["Fetch Pexels Videos"].json.video_urls || [];
const subtitles = $node["Parse & Extract JSON"].json.script.subtitles || [];

const readyPayload = {
  job_id: jobId,
  status: 'ready',
  user_id: userId,
  audio_url: audioUrl,
  b_roll_videos: videoUrls,
  subtitles: subtitles
};

const signature = crypto.createHmac('sha256', secret).update(JSON.stringify(readyPayload)).digest('hex');

return [{
  json: {
    payload: readyPayload,
    signature: signature
  }
}];

const crypto = require('crypto');
const secret = process.env.REELSFLOW_SIGNATURE_SECRET || 'sua-chave-secreta-para-assinatura-hmac-aqui';

let jobId = '00000000-0000-0000-0000-000000000000';
let userId = null;
let errorMessage = 'Falha genérica no processamento da automação do n8n.';

try {
  const triggerData = $node["Verify HMAC Signature"].json;
  if (triggerData && triggerData.job_id) {
    jobId = triggerData.job_id;
    userId = triggerData.user_id;
  }
} catch (e) {
  try {
    const errorData = $input.first().json;
    errorMessage = errorData.message || errorMessage;
  } catch (err) {}
}

const failedPayload = {
  job_id: jobId,
  status: 'failed',
  error_message: errorMessage,
  user_id: userId
};

const signature = crypto.createHmac('sha256', secret).update(JSON.stringify(failedPayload)).digest('hex');

return [{
  json: {
    payload: failedPayload,
    signature: signature
  }
}];
